import{_ as l,c as s,o as e,ag as n}from"./chunks/framework.D4Vqf8I7.js";const h=JSON.parse('{"title":"PROJEKT: OVERFLOW RISC-V assembly board game","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/games/board/projeckt_overflow.md","filePath":"docs/wi/games/board/projeckt_overflow.md","lastUpdated":1781771470000}'),i={name:"docs/wi/games/board/projeckt_overflow.md"};function r(p,a,o,t,d,c){return e(),s("div",null,a[0]||(a[0]=[n(`<h1 id="projekt-overflow-risc-v-assembly-board-game" tabindex="-1">PROJEKT: OVERFLOW RISC-V assembly board game <a class="header-anchor" href="#projekt-overflow-risc-v-assembly-board-game" aria-label="Permalink to &quot;PROJEKT: OVERFLOW RISC-V assembly board game&quot;">​</a></h1><p>hack the planet</p><p><a href="https://punkx.org/overflow/" target="_blank" rel="noreferrer">https://punkx.org/overflow/</a></p><p><img src="https://punkx.org/overflow/logo.svg" alt="Logo"></p><ul><li><a href="./local.html">ИГРАТЬ В ВЕБ-ВЕРСИЮ: ОДИН</a></li><li><a href="./remote.html">ИГРАТЬ В ВЕБ-ВЕРСИЮ: С ДРУГОМ</a></li><li><a href="#print">ПЕЧАТЬ</a></li><li><a href="#rules">ПРАВИЛА</a></li><li><a href="#other">ПОХОЖИЕ ПРОЕКТЫ</a></li><li><a href="#symbols">СИМВОЛЫ</a></li><li><a href="#credits">БЛАГОДАРНОСТИ</a></li><li><a href="#contact">КОНТАКТЫ</a></li><li><a href="./esp32.html">ПОМОЩНИК ДЛЯ ИГРЫ: ESP32</a> | <a href="./helper.html">МОБИЛЬНЫЙ</a></li><li><a href="#assembly">РУКОВОДСТВО ПО СБОРКЕ</a></li></ul><hr><h2 id="игра" tabindex="-1"><span id="game">ИГРА</span> <a class="header-anchor" href="#игра" aria-label="Permalink to &quot;&lt;span id=&quot;game&quot;&gt;ИГРА&lt;/span&gt;&quot;">​</a></h2><p>Я создал эту игру, чтобы научить свою дочь тому, как работают переполнения буфера. Моя любимая часть в вычислениях — возможность относиться к программам как к чему-то, с чем можно играть, экспериментировать, изменять и делать их такими, какими вы хотите. Когда ваша микроволновка получает обновление и начинает зависать — вы можете её взломать. Или когда прошивка контроллера клавиатуры работает плохо — вы можете её взломать (привет, Vortex Pok3r). Сейчас ей 12 лет, но её навыки в ассемблере становятся всё лучше и лучше — надеюсь, однажды она сможет взломать свою собственную клавиатуру 😃</p><p>Игра заключается в создании небольшого шеллкода в памяти путём копирования существующих инструкций, а затем использовании <a href="http://phrack.org/issues/49/14.html#article" target="_blank" rel="noreferrer">переполнения буфера</a> для перехода в него, чтобы вы могли перезаписать адрес возврата оппонента и заставить его перейти к функции <code>game_over()</code>. Есть и другие механики, а также дополнительные слои стратегии (например, установка обработчика исключений или «монкипатчинг»).</p><p>Все игроки используют одну и ту же память и выполняют одну и ту же программу, при этом совместно используют один процессор с операционной системой, реализующей <a href="https://en.wikipedia.org/wiki/Preemption_(computing)" target="_blank" rel="noreferrer">вытесняющую многозадачность</a>. Каждый ход игрок выполняет 10 инструкций, после чего процесс прерывается операционной системой, и наступает ход другого игрока. Указатель стека (stack pointer) каждого игрока начинается с разного адреса. Виртуальная память отсутствует.</p><p>Как выглядит игра, когда мы играем с друзьями (доказательство того, что люди действительно играют в эту игру, и также того, что у меня есть друзья):</p><p><img src="https://punkx.org/overflow/friends.jpg" alt="Friends playing"></p><p>С моей дочерью и собакой:</p><p><img src="https://punkx.org/overflow/play.jpg" alt="Playing with kid"></p><p>Код компилируется следующей командой:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">riscv64-unknown-elf-gcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fomit-frame-pointer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fno-inline-small-functions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -mno-shorten-memrefs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -march=rv32g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mabi=ilp32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ffreestanding</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nostdlib</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -nostartfiles</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code/link.ld</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fverbose-asm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> game</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> game.c</span></span></code></pre></div><p>Скрипт линковщика <code>link.ld</code> содержит только смещения для конкретных функций, чтобы они хорошо помещались на игровом поле. Отсутствие оптимизации <code>-O0</code> делает машинный код довольно многословным, но при этом понятным. Затем я использую:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">riscv64-unknown-elf-objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> game</span></span></code></pre></div><p>Паршу вывод, исправляю инструкции ▲ и ✎, конвертирую смещения переходов из шестнадцатеричного формата в десятичный, немного очищаю ассемблерный код, сопоставляю его с исходным кодом и генерирую SVG, который затем конвертирую в PDF с помощью Inkscape.</p><hr><h2 id="печать" tabindex="-1"><span id="print">ПЕЧАТЬ</span> <a class="header-anchor" href="#печать" aria-label="Permalink to &quot;&lt;span id=&quot;print&quot;&gt;ПЕЧАТЬ&lt;/span&gt;&quot;">​</a></h2><ul><li><a href="build/game-l.pdf">Игровое поле: левая часть [A3 или A4 PDF]</a></li><li><a href="build/game-r.pdf">Игровое поле: правая часть [A3 или A4 PDF]</a></li><li><a href="build/mem-1984.pdf">Шаблон памяти для игроков 1,3 (адреса 1988–2244) [A4 PDF]</a></li><li><a href="build/mem-3584.pdf">Шаблон памяти для игроков 2,4 (адреса 3588–3840) [A4 PDF]</a></li></ul><p><strong>Предпросмотр игрового поля:</strong></p><p><a href="build/game-l.pdf"><img src="https://punkx.org/overflow/build/game-l-thumb.jpg" alt="Left board"></a><a href="build/game-r.pdf"><img src="https://punkx.org/overflow/build/game-r-thumb.jpg" alt="Right board"></a></p><h3 id="требования-к-оборудованию" tabindex="-1">Требования к оборудованию <a class="header-anchor" href="#требования-к-оборудованию" aria-label="Permalink to &quot;Требования к оборудованию&quot;">​</a></h3><ul><li><strong>Принтер:</strong> предпочтительно A3, A4 тоже подойдёт, но будет немного мелко</li><li><strong>Фишки:</strong> 1 фишка для свободной инструкции <strong>nop</strong>, одна фишка для адреса ловушки (trap), и по 2 фишки на игрока — одна для счётчика команд (program counter), одна для указателя стека (stack pointer). Я использую конденсаторы с обрезанными ножками или колпачки от велосипедных ниппелей</li><li><strong>Карандаш и ластик</strong></li></ul><hr><h2 id="правила-игры" tabindex="-1"><span id="rules">ПРАВИЛА ИГРЫ</span> <a class="header-anchor" href="#правила-игры" aria-label="Permalink to &quot;&lt;span id=&quot;rules&quot;&gt;ПРАВИЛА ИГРЫ&lt;/span&gt;&quot;">​</a></h2><p><span style="color:red;font-size:20px;">✱</span> <strong>Настройка игрового поля:</strong></p><ol><li>Оба игрока начинают со всеми регистрами, установленными в ноль, за исключением регистра адреса возврата (<code>ra</code>), который начинается со значения 1000.</li><li>Указатель стека (<code>sp</code>) Игрока 1 инициализируется по адресу 2244.</li><li>Указатель стека (<code>sp</code>) Игрока 2 инициализируется по адресу 3844.</li><li>Фишка инструкции <strong>nop</strong> изначально не размещается на поле.</li><li>Счётчики команд (<code>pc</code>) обоих игроков начинаются с адреса 1000 — начала функции <code>main</code>.</li><li>Разместите фишку ловушки (trap) по адресу 1000.</li><li>Все адреса памяти установлены в ноль, за исключением предварительно загруженной программы.</li></ol><p><span style="color:red;font-size:20px;">✱</span> <strong>Игровой процесс:</strong></p><ol><li><strong>Ходы за ход:</strong> Игроки обязаны выполнить 10 инструкций за свой ход.</li><li><strong>Выполнение инструкций:</strong> Игроки должны следовать за счётчиком команд и выполнить либо 10 инструкций, либо накопленное количество до 20. Все переходы (<code>jal</code>, <code>beq</code> и т.д.) должны соблюдаться.</li><li><strong>Приостановка выполнения:</strong> Игроки могут решить приостановить свой ход после выполнения хотя бы одной инструкции, сохранив оставшиеся инструкции для следующего хода. Максимальное накопленное количество — 20 инструкций.</li><li><strong><a href="https://en.wikipedia.org/wiki/Monkey_patch" target="_blank" rel="noreferrer">Монкипатч</a>:</strong> После выполнения ровно одной инструкции в начале каждого хода игрок может переместить фишку инструкции <code>nop</code> на любой адрес в любой функции, которая в данный момент не выполняется игроками. Когда счётчик команд достигнет этого адреса, инструкция будет действовать как «нет операции» (nop). Перемещение фишки <code>nop</code> стоит игроку текущего и следующего хода, позволяя оппоненту выполнить до 20 инструкций в свой следующий ход. <em>Механика монкипатча всё ещё несбалансирована — каждые несколько дней я немного меняю правило в попытке улучшить его, так что если у вас есть лучшая идея, дайте мне знать.</em></li></ol><p><span style="color:rgba(255,0,0,1);font-size:20px;">◉</span> <strong>Условия победы [СЛОЖНЫЙ РЕЖИМ]:</strong></p><ol><li><strong>Game Over:</strong> Игра заканчивается, когда один игрок успешно «взламывает» оппонента, заставляя его вызвать функцию <code>game_over()</code>.</li><li><strong>Ничья:</strong> Возможно, игра зайдёт в состояние, когда никто не может заставить другого игрока перейти в <code>game_over()</code> — в этом случае игра заканчивается вничью.</li></ol><p><span style="color:rgba(255,0,0,1);font-size:20px;">⊙</span> <strong>Условия победы [ПРОСТОЙ РЕЖИМ]:</strong></p><ol><li><strong>Освобождение:</strong> Победителем становится первый игрок, вышедший из основного цикла (выполнивший <strong>ret</strong> в функции <code>main</code>).</li></ol><p><span style="color:red;font-size:20px;">✱</span> <strong>Специальные символы:</strong></p><ol><li><span style="font-size:20px;">✎</span>: Этот символ позволяет игрокам выбрать любое 12-битное число (от 0 до 4095) в качестве непосредственного значения в инструкции <code>li</code>.</li><li><span style="font-size:20px;">▲</span>: Этот символ позволяет игрокам выбрать значение для инструкции загрузки в пределах ±128 байт от их указателя стека. Например, если ваш <code>sp</code> равен 2180, вы можете выбрать значение между 2052 и 2308.</li></ol><p><span style="color:red;font-size:20px;">✱</span> <strong>Правила и ограничения:</strong></p><ol><li><strong>Незаконные действия:</strong> Перезапись адреса памяти ниже 1192, невыровненное чтение или запись (чтение/запись по адресу, не кратному 4) или выполнение незаконной инструкции приведёт к краху вашей программы.</li><li><strong>Обработка исключений:</strong> Крах вызывает обработчик исключений, который переходит по адресу ловушки (изначально 1000, но его можно перезаписать из функции <code>set_trap()</code>). После возникновения исключения счётчик команд устанавливается в указанное значение, и выполнение продолжается.</li><li><strong>Читерство/Ошибки:</strong> Если игрок читерит или допускает ошибку и его ловят, состояние его программы, включая память и регистры, сбрасывается.</li></ol><p><strong>Расширенные правила для большего количества игроков:</strong></p><ol><li>Регистр указателя стека (<code>sp</code>) Игрока 3 устанавливается в 2116.</li><li>Регистр указателя стека (<code>sp</code>) Игрока 4 устанавливается в 3716.</li><li>Символ <span style="font-size:20px;">▲</span> теперь позволяет записывать только на -128 байт от вашего указателя стека.</li><li>Игра будет довольно нестабильной с более чем 2 игроками и быстро «повредится». Достичь условия победы будет сложнее, но игровой процесс станет более весёлым и хаотичным.</li></ol><p><strong>Подсказки и стратегии:</strong></p><ol><li><p><strong>Офензивные краши:</strong> Используйте краши как наступательную стратегию для нарушения игрового процесса оппонента.</p></li><li><p><strong>Модификация обработчика ловушек:</strong> Измените обработчик ловушек так, чтобы он указывал на функцию <code>game_over</code> — тогда первый игрок, получивший крах, проиграет. <strong>Внимание:</strong> фишка <strong>nop</strong> — чрезвычайно мощный инструмент, если ловушка установлена на <code>game_over</code>, потому что вы можете поместить её поверх <strong>ret</strong> в функции, которую в данный момент выполняет оппонент, и он проиграет.</p></li><li><p><strong>Перезапись адреса возврата:</strong> Используйте функцию <code>bug()</code>, чтобы перезаписать адрес возврата оппонента, переполнив индекс значением 400 или -400, что позволит получить доступ к стеку другого игрока. Например, чтобы перейти с адреса 3784 (<code>buffer[0]</code> с указателем стека 3780) на адрес 2184, требуется индекс -400, вычисляемый как (3784 - 2184) / 4 = 400.</p></li><li><p><strong>Создание шеллкода:</strong> Используйте функцию <code>copy()</code>, чтобы скопировать конкретные инструкции и сформировать компактный шеллкод в своей памяти, позволяющий произвольные записи. Используйте переполнение буфера в функции <code>bug()</code>, чтобы перейти в этот шеллкод. Пример простого шеллкода для произвольной записи:</p><ul><li><code>li a4, ✎</code> (копировать с адреса 256, 268)</li><li><code>li a5, ✎</code> (доступно по адресам 136, 144, 1016 и т.д.)</li><li><code>sw a4, 0(a5)</code> (доступно по адресам 264, 272)</li><li><code>ret</code> (доступно по адресам 272, 200, 1060 и т.д.)</li></ul><p>Копирование инструкции <code>ret</code> приведёт к бесконечному циклу, так как адрес возврата будет установлен на начало шеллкода при переходе в него, вызывая непрерывное выполнение.</p></li><li><p><strong>Переход в память:</strong> Чтобы перейти в свою память, используйте переполнение буфера в функции <code>bug()</code>. Установив переменную <code>index</code> в значение 6, вы можете записать переменную <code>value</code> поверх сохранённого адреса возврата в стеке (28(sp)). При возврате из <code>bug()</code> программа копирует значение из 28(sp) в регистр адреса возврата. Поместите адрес созданного вами шеллкода в переменную <code>value</code>.</p></li></ol><blockquote><p><strong>Примечание:</strong> Все переходы относительны к текущему счётчику команд, даже если они отображаются как абсолютные адреса в дизассемблере. Например, <code>jal a4, 0</code> (машинный код 1903) на самом деле является бесконечным циклом при выполнении.</p></blockquote><details><summary>Список всех допустимых инструкций игры с машинным кодом от 0 до 4095 (RV32 JRI, работающие с a0, a4, a5, sp, ra)</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0x00000013 (19)  addi zero, zero, 0</span></span>
<span class="line"><span>0x00000033 (51)  add zero, zero, zero</span></span>
<span class="line"><span>0x00000067 (103) jalr zero, zero, 0</span></span>
<span class="line"><span>0x0000006f (111) jal zero, 0</span></span>
<span class="line"><span>0x00000093 (147) addi ra, zero, 0</span></span>
<span class="line"><span>0x000000b3 (179) add ra, zero, zero</span></span>
<span class="line"><span>0x000000e7 (231) jalr ra, zero, 0</span></span>
<span class="line"><span>0x000000ef (239) jal ra, 0</span></span>
<span class="line"><span>0x00000113 (275) addi sp, zero, 0</span></span>
<span class="line"><span>0x00000133 (307) add sp, zero, zero</span></span>
<span class="line"><span>0x00000167 (359) jalr sp, zero, 0</span></span>
<span class="line"><span>0x0000016f (367) jal sp, 0</span></span>
<span class="line"><span>0x00000513 (1299) addi a0, zero, 0</span></span>
<span class="line"><span>0x00000533 (1331) add a0, zero, zero</span></span>
<span class="line"><span>0x00000567 (1383) jalr a0, zero, 0</span></span>
<span class="line"><span>0x0000056f (1391) jal a0, 0</span></span>
<span class="line"><span>0x00000593 (1427) addi a1, zero, 0</span></span>
<span class="line"><span>0x000005b3 (1459) add a1, zero, zero</span></span>
<span class="line"><span>0x000005e7 (1511) jalr a1, zero, 0</span></span>
<span class="line"><span>0x000005ef (1519) jal a1, 0</span></span>
<span class="line"><span>0x00000613 (1555) addi a2, zero, 0</span></span>
<span class="line"><span>0x00000633 (1587) add a2, zero, zero</span></span>
<span class="line"><span>0x00000667 (1639) jalr a2, zero, 0</span></span>
<span class="line"><span>0x0000066f (1647) jal a2, 0</span></span>
<span class="line"><span>0x00000713 (1811) addi a4, zero, 0</span></span>
<span class="line"><span>0x00000733 (1843) add a4, zero, zero</span></span>
<span class="line"><span>0x00000767 (1895) jalr a4, zero, 0</span></span>
<span class="line"><span>0x0000076f (1903) jal a4, 0</span></span>
<span class="line"><span>0x00000793 (1939) addi a5, zero, 0</span></span>
<span class="line"><span>0x000007b3 (1971) add a5, zero, zero</span></span>
<span class="line"><span>0x000007e7 (2023) jalr a5, zero, 0</span></span>
<span class="line"><span>0x000007ef (2031) jal a5, 0</span></span></code></pre></div></details><details><summary>Журнал изменений</summary><p><strong>0.0.6:</strong> заменено <code>while(run)</code> на <code>while(*prun)</code>, чтобы оппонент мог намеренно вызвать краш, заставив выполнить невыровненную разыменовку; изменено правило NOP — теперь его можно размещать только в функциях, которые в данный момент не выполняются.</p></details><h2 id="символы" tabindex="-1"><span id="symbols">СИМВОЛЫ</span> <a class="header-anchor" href="#символы" aria-label="Permalink to &quot;&lt;span id=&quot;symbols&quot;&gt;СИМВОЛЫ&lt;/span&gt;&quot;">​</a></h2><p>Квадраты слева/справа содержат двоичное сообщение, закодированное в ASCII — попробуйте расшифровать его: белые квадраты — это 1, чёрные на чёрном — 0, используйте интервалы, чтобы понять, где находятся нули.</p><p>Цвета минимальны, чтобы люди могли печатать дёшево, и чтобы всё было чётко видно на чёрно-белых принтерах A3 и A4. Используются только цвета: красный (255,0,0), синий (0,0,255), чёрный (0,0,0) и белый (255,255,255).</p><p>Я не дизайнер, но текущий дизайн — это, возможно, 20-я итерация, и он появился после 5 часов прослушивания <a href="https://www.youtube.com/watch?v=iTPNaUsjksM" target="_blank" rel="noreferrer">Making of a Cyborg</a> из <em>Ghost in the Shell</em>.</p><p>Логотип проекта символизирует переполнение и сгенерирован случайным образом. Текущее случайное зерно вызвало у меня лёгкое беспокойство, поэтому я оставил его как есть.</p><p>Интервалы в логотипе и японском тексте немного смещены — это сделано для того, чтобы можно было сложить бумагу A3 пополам, не задевая текст.</p><p>Японский текст — это последние слова Короля Пиратов, <a href="https://www.youtube.com/watch?v=UFVL45xAPSY" target="_blank" rel="noreferrer">Гол Д. Роджера</a>: <em>«Унаследованная воля, судьба эпохи и мечты людей. Пока люди продолжают стремиться к смыслу Свободы, эти вещи никогда не перестанут существовать!»</em></p><p><strong>Без подсветки синтаксиса.</strong> Я не использую подсветку синтаксиса и не учу свою дочь её использовать. У меня нет сильных предпочтений, но подсветка заставляет думать, что определённые вещи в коде важнее других (в зависимости от темы). Без подсветки я могу сам решать, на чём сосредоточиться, и легко фокусироваться на том, что считаю важным.</p><hr><h2 id="благодарности" tabindex="-1"><span id="credits">БЛАГОДАРНОСТИ</span> <a class="header-anchor" href="#благодарности" aria-label="Permalink to &quot;&lt;span id=&quot;credits&quot;&gt;БЛАГОДАРНОСТИ&lt;/span&gt;&quot;">​</a></h2><p>Я хочу поблагодарить Питера, Уильяма, Шантану, Рареса и мою дочь, которые сыграли в 50 разных версий игры — все они были довольно плохими 😃, но они не сдались. Спасибо tn1, который очень помог мне с дизайном, особенно указывая на то, что не работает.</p><p>Также большая благодарность людям, работающим над <a href="https://terminus-font.sourceforge.net/" target="_blank" rel="noreferrer">шрифтом Terminus</a> — это абсолютная красота.</p><p>Отдельное спасибо <a href="https://github.com/OpenMachine-ai/tinyfive" target="_blank" rel="noreferrer">эмулятору tinyfive от OpenMachine</a>, который я использовал для тестирования игры, пока не написал свой собственный для веб-версии.</p><p>Спасибо <a href="https://gamesounds.xyz/" target="_blank" rel="noreferrer">gamesounds.xyz</a> за .wav-файлы для веб-версии, а также Карлу Кейси @ White Bat Audio за фоновую музыку.</p><p>И, конечно, огромная благодарность людям, работающим над RISC-V — с ним супер-весело работать.</p><p>Большое спасибо <a href="https://twitter.com/matsuu" target="_blank" rel="noreferrer">@matsuu</a> за указание на опечатку в японском написании.</p><hr><h2 id="контакты" tabindex="-1"><span id="contact">КОНТАКТЫ</span> <a class="header-anchor" href="#контакты" aria-label="Permalink to &quot;&lt;span id=&quot;contact&quot;&gt;КОНТАКТЫ&lt;/span&gt;&quot;">​</a></h2><p><strong>Email:</strong> <a href="mailto:jackdoe@fastmail.com" target="_blank" rel="noreferrer">jackdoe@fastmail.com</a></p><p>Если у вас есть идея по поводу другого игрового поля или правил, или вы нашли ошибку в поле или онлайн-версии — пожалуйста, напишите мне. Также оказалось, что я могу играть в эту игру с дочерью и примерно двумя людьми из всего моего списка контактов 🥹, так что если вам понравилось играть — я буду рад услышать об этом.</p><hr><h2 id="руководство-по-ассемблеру" tabindex="-1"><span id="assembly">РУКОВОДСТВО ПО АССЕМБЛЕРУ</span> <a class="header-anchor" href="#руководство-по-ассемблеру" aria-label="Permalink to &quot;&lt;span id=&quot;assembly&quot;&gt;РУКОВОДСТВО ПО АССЕМБЛЕРУ&lt;/span&gt;&quot;">​</a></h2><p>Вы можете найти множество руководств по ассемблеру RISC-V, например:</p><ul><li><a href="https://riscv-programming.org/" target="_blank" rel="noreferrer">riscv-programming.org</a></li><li><a href="https://github.com/riscv-non-isa/riscv-asm-manual/blob/master/riscv-asm.md" target="_blank" rel="noreferrer">riscv-asm-manual</a></li></ul><p>И множество интерпретаторов, например:</p><ul><li><a href="https://www.cs.cornell.edu/courses/cs3410/2019sp/riscv/interpreter/" target="_blank" rel="noreferrer">Интерпретатор CS3410 RISC-V</a></li></ul><p>И декодеры, например <a href="https://luplab.gitlab.io/rvcodecjs/" target="_blank" rel="noreferrer">rvcodecjs от luplab</a> — отличный декодер инструкций: введите туда <code>0x13</code> (инструкция nop) и посмотрите, как она декодируется.</p><p>Если у вас возникают трудности, вы также можете поискать на YouTube «risc v assembly tutorial» — там много действительно хороших видео. К сожалению, я не уверен, какое подойдёт именно вам, так что не унывайте и просто попробуйте несколько из них.</p><p>Я подготовил упражнения для своей дочери: каждый день я печатал несколько <a href="build/mem-1984.pdf">шаблонов памяти</a> и несколько примеров кода ниже, и она просто выполняла инструкции. Иногда я менял код на лету или тратил больше времени на объяснение, например, приведения типов и структур. Но базовый ассемблер RISC-V она смогла понять довольно быстро.</p><p><strong>Версия «Виселица»</strong> — это тот же обычный PDF, но некоторые инструкции ассемблера пропущены, и вам нужно их вписать:</p><p><img src="https://punkx.org/overflow/hangman.png" alt="Hangman example"></p><p>Если вам нужно подтянуть знания по C, мы используем руководство Бижда: <a href="https://beej.us/guide/bgc/html/split/" target="_blank" rel="noreferrer">Beej&#39;s Guide to C Programming</a>, особенно первые 7–8 глав. Но есть много других отличных ресурсов. Вы также можете использовать следующие примеры ассемблера, чтобы освежить знания по C — хороший пример: <a href="https://punkx.org/overflow/build/l1-pointers-1.pdf" target="_blank" rel="noreferrer">упражнение с указателями</a>:</p><p><a href="https://punkx.org/overflow/build/l1-pointers-1.pdf" target="_blank" rel="noreferrer"><img src="https://punkx.org/overflow/pointers-1.png" alt="Pointers exercise"></a></p><p>Когда вы печатаете упражнение и шаблон памяти, это выглядит так:</p><p><img src="https://punkx.org/overflow/printed.png" alt="Printed example"></p><p><strong>Список выполненных упражнений:</strong></p><ul><li><a href="build/l0-variables-0.pdf">l0-variables-0.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l0-variables-0.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l0-variables-1.pdf">l0-variables-1.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l0-variables-1.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l0-variables-2.pdf">l0-variables-2.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l0-variables-2.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-1.pdf">l1-call-function-1.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-1.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-2.pdf">l1-call-function-2.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-2.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-3.pdf">l1-call-function-3.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-3.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-4.pdf">l1-call-function-4.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-4.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-5.pdf">l1-call-function-5.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-5.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-6.pdf">l1-call-function-6.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-6.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-7.pdf">l1-call-function-7.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-7.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-8.pdf">l1-call-function-8.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-8.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-9.pdf">l1-call-function-9.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-9.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-10.pdf">l1-call-function-10.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-10.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-11.pdf">l1-call-function-11.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-11.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-12.pdf">l1-call-function-12.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-12.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-13.pdf">l1-call-function-13.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-13.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-call-function-14.pdf">l1-call-function-14.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-call-function-14.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-pointers-0.pdf">l1-pointers-0.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-pointers-0.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-pointers-1.pdf">l1-pointers-1.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-pointers-1.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-string-0.pdf">l1-string-0.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-string-0.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-string-1.pdf">l1-string-1.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-string-1.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-string-2.pdf">l1-string-2.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-string-2.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l1-struct-0.pdf">l1-struct-0.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l1-struct-0.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l2-array-1.pdf">l2-array-1.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l2-array-1.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l2-array-2.pdf">l2-array-2.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l2-array-2.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l2-array-3.pdf">l2-array-3.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l2-array-3.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l2-recursion-0.pdf">l2-recursion-0.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l2-recursion-0.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li><li><a href="build/l2-recursion-1.pdf">l2-recursion-1.pdf [A3 или A4 PDF]</a> | <a href="build/f03/l2-recursion-1.pdf">ВЕРСИЯ «ВИСЕЛИЦА»</a></li></ul><blockquote><p>Все изображения и ссылки сохранены в оригинальном формате. Для корректного отображения некоторых элементов (например, <code>&lt;details&gt;</code>) в вашем Markdown-просмотрщике может потребоваться поддержка HTML.</p></blockquote>`,85)]))}const g=l(i,[["render",r]]);export{h as __pageData,g as default};
